blocks.body:
{
  "level": "B1",
  "intro": "W tym temacie nauczysz się tworzyć <strong>Future Simple Passive</strong> oraz używać go w przewidywaniach, ogłoszeniach i obietnicach.",
  "rules": [
    {
      "label": "Wzór",
      "color": "emerald",
      "text": "<strong>subject + will be + V3</strong>:",
      "example": "The letter will be sent tomorrow."
    },
    {
      "label": "Przeczenie",
      "color": "rose",
      "text": "<strong>subject + will not be + V3</strong>:",
      "example": "The letter will not be sent today."
    },
    {
      "label": "Pytanie",
      "color": "blue",
      "text": "<strong>Will + subject + be + V3?</strong>:",
      "example": "Will the letter be sent on time?"
    }
  ]
}

{
  "title": "1. Budowa Future Simple Passive",
  "intro": "<strong>Will</strong> jest takie samo dla wszystkich osób, a <strong>be</strong> pozostaje niezmienne:",
  "items": [
    {
      "label": "Wszystkie osoby",
      "title": "will be + V3",
      "subtitle": "I / You / He / She / It / We / They will be invited."
    },
    {
      "label": "Liczba pojedyncza",
      "title": "will be + V3",
      "subtitle": "The report will be submitted."
    },
    {
      "label": "Liczba mnoga",
      "title": "will be + V3",
      "subtitle": "All the tasks will be completed."
    },
    {
      "label": "Uwaga",
      "title": "will be jest stałe",
      "subtitle": "Między <strong>will</strong> a <strong>V3</strong> zawsze stoi <strong>be</strong>."
    }
  ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Kolejność słów: <strong>podmiot + będzie + V3 (+ przez agenta)</strong>",
            "examples": [
                {
                    "en": "The results will be announced tomorrow.",
                    "ua": "Wyniki zostaną ogłoszone jutro."
                },
                {
                    "en": "The meeting will be held next Monday.",
                    "ua": "Spotkanie odbędzie się w najbliższy poniedziałek."
                },
                {
                    "en": "You will be contacted soon.",
                    "ua": "Wkrótce się z Tobą skontaktujemy."
                },
                {
                    "en": "The project will be completed by the team.",
                    "ua": "Projekt zostanie zrealizowany przez zespół."
                }
            ]
        },
        {
            "label": "Z instrukcjami wykonawcy",
            "color": "sky",
            "description": "Kiedy ważne jest określenie, <strong>kto wykona akcję</strong>:",
            "examples": [
                {
                    "en": "The decision will be made by the board.",
                    "ua": "Decyzję podejmie rada."
                },
                {
                    "en": "The cake will be baked by my mother.",
                    "ua": "Ciasto zostało upieczone przez moją mamę."
                },
                {
                    "en": "The email will be sent by the secretary.",
                    "ua": "List wyśle ​​sekretarz."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy używać Future Simple Passive?",
    "sections": [
        {
            "label": "Plany i prognozy",
            "color": "emerald",
            "description": "W przypadku działań, które <strong>wystąpią w przyszłości</strong>:",
            "examples": [
                {
                    "en": "The new bridge will be built next year.",
                    "ua": "Nowy most powstanie w przyszłym roku."
                },
                {
                    "en": "The package will be delivered tomorrow.",
                    "ua": "Przesyłka zostanie dostarczona jutro."
                },
                {
                    "en": "The guests will be welcomed at the entrance.",
                    "ua": "Goście zostaną powitani przy wejściu."
                }
            ]
        },
        {
            "label": "Oficjalne ogłoszenia",
            "color": "blue",
            "description": "W <strong>oficjalnych komunikatach i ogłoszeniach</strong>:",
            "examples": [
                {
                    "en": "The winner will be announced at 5 PM.",
                    "ua": "Zwycięzca zostanie ogłoszony o godzinie 17:00."
                },
                {
                    "en": "All applicants will be notified by email.",
                    "ua": "Wszyscy kandydaci zostaną powiadomieni e-mailem."
                },
                {
                    "en": "The office will be closed for renovation.",
                    "ua": "Z powodu remontu biuro będzie nieczynne."
                }
            ]
        },
        {
            "label": "Obietnice i zapewnienia",
            "color": "amber",
            "description": "W przypadku <strong>obietnic</strong> i <strong>zapewnień</strong>:",
            "examples": [
                {
                    "en": "Your complaint will be addressed immediately.",
                    "ua": "Twoja skarga zostanie rozpatrzona natychmiast."
                },
                {
                    "en": "You will be given a full refund.",
                    "ua": "Otrzymasz pełny zwrot pieniędzy."
                },
                {
                    "en": "The problem will be solved as soon as possible.",
                    "ua": "Problem zostanie rozwiązany tak szybko, jak to możliwe."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Dodaj <strong>not</strong> po will: <strong>podmiot + nie będzie (nie będzie) + V3</strong>",
            "examples": [
                {
                    "en": "The project will not be finished on time.",
                    "ua": "Projekt nie zostanie ukończony w terminie."
                },
                {
                    "en": "The documents will not be signed today.",
                    "ua": "Dokumenty nie zostaną dzisiaj podpisane."
                },
                {
                    "en": "The meeting will not be held tomorrow.",
                    "ua": "Jutro spotkanie nie odbędzie się."
                },
                {
                    "en": "You will not be charged for this service.",
                    "ua": "Za tę usługę nie zostaną Państwo pobrani żadne opłaty."
                }
            ]
        },
        {
            "label": "Skrócona forma",
            "color": "amber",
            "description": "Potocznie: <strong>nie będzie</strong>",
            "examples": [
                {
                    "en": "The email won't be sent until Monday.",
                    "ua": "List zostanie wysłany dopiero w poniedziałek."
                },
                {
                    "en": "The tickets won't be available online.",
                    "ua": "Bilety nie będą dostępne online."
                },
                {
                    "en": "The decision won't be made today.",
                    "ua": "Żadna decyzja nie zostanie dziś podjęta."
                }
            ]
        }
    ]
}

{
    "title": "5. Zdania pytające",
    "sections": [
        {
            "label": "Pytania yes/no",
            "color": "blue",
            "description": "<strong>Will</strong> jest na pierwszym miejscu: <strong>Czy + podmiot + będzie + V3?</strong>",
            "examples": [
                {
                    "en": "Will the report be ready by Friday?",
                    "ua": "Czy raport będzie gotowy do piątku?"
                },
                {
                    "en": "Will the meeting be held online?",
                    "ua": "Czy spotkanie odbędzie się online?"
                },
                {
                    "en": "Will we be informed about the changes?",
                    "ua": "Czy zostaniemy powiadomieni o zmianach?"
                },
                {
                    "en": "Will the package be delivered tomorrow?",
                    "ua": "Czy paczka zostanie jutro dostarczona?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Wh-word + będzie + podmiot + będzie + V3?</strong>",
            "examples": [
                {
                    "en": "When will the results be announced?",
                    "ua": "Kiedy zostaną ogłoszone wyniki?"
                },
                {
                    "en": "Where will the event be held?",
                    "ua": "Gdzie odbędzie się wydarzenie?"
                },
                {
                    "en": "How will the problem be solved?",
                    "ua": "Jak rozwiązać problem?"
                },
                {
                    "en": "Why will the office be closed?",
                    "ua": "Dlaczego urząd będzie zamknięty?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "Odpowiedzi zawierające <strong>Tak/Nie + zaimek + will (nie)</strong>:",
            "examples": [
                {
                    "en": "Will the email be sent? — Yes, it will. / No, it won't.",
                    "ua": "Czy list zostanie wysłany? - Tak. / NIE."
                },
                {
                    "en": "Will they be invited? — Yes, they will. / No, they won't.",
                    "ua": "Czy zostaną zaproszeni? - Tak. / NIE."
                }
            ]
        }
    ]
}

{
    "title": "6. Porównanie aktywnego i pasywnego w czasie Future Simple",
    "intro": "Jak zamienić zdanie czynne w stronę bierną:",
    "rows": [
        {
            "en": "Active: They will send the letter tomorrow.",
            "ua": "Jutro wyślą pismo.",
            "note": "→ Passive: The letter will be sent tomorrow."
        },
        {
            "en": "Active: The company will hire new staff.",
            "ua": "Firma zatrudni nowych pracowników.",
            "note": "→ Passive: New staff will be hired."
        },
        {
            "en": "Active: Someone will repair the car.",
            "ua": "Ktoś naprawi samochód.",
            "note": "→ Passive: The car will be repaired."
        },
        {
            "en": "Active: We will hold the meeting next week.",
            "ua": "W przyszłym tygodniu mamy spotkanie.",
            "note": "→ Passive: The meeting will be held next week."
        }
    ],
    "warning": "📌 Oznaczenia czasu (jutro, za tydzień, wkrótce) pozostają!"
}

{
    "title": "7. Znaczniki czasu dla przyszłej prostej biernej",
    "intro": "Typowe słowa i wyrażenia wskazujące na czas Future Simple:",
    "items": [
        {
            "label": "Jutro",
            "title": "jutro, pojutrze",
            "subtitle": "Raport zostanie złożony jutro."
        },
        {
            "label": "Następny",
            "title": "w przyszłym tygodniu/miesiącu/roku",
            "subtitle": "Zakończenie projektu nastąpi w przyszłym miesiącu."
        },
        {
            "label": "Wkrótce",
            "title": "wkrótce, wkrótce, za kilka dni",
            "subtitle": "Wkrótce się z Tobą skontaktujemy."
        },
        {
            "label": "Konkretny czas",
            "title": "o godzinie 17:00 w poniedziałek w 2025 roku",
            "subtitle": "Wyniki zostaną ogłoszone o godzinie 17:00."
        }
    ]
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak be.",
            "wrong": "The letter will sent tomorrow.",
            "right": "✅ The letter will be sent tomorrow."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie V1 zamiast V3.",
            "wrong": "The report will be write.",
            "right": "✅ The report will be written."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Kolejność słów w pytaniu jest nieprawidłowa.",
            "wrong": "Will be the meeting held?",
            "right": "✅ Will the meeting be held?"
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Podwójna wola.",
            "wrong": "The project will will be completed.",
            "right": "✅ The project will be completed."
        }
    ]
}
